// MARK: - Wallet Model
struct Wallet {
    let address: String
    let privateKey: Data
    let publicKey: Data
    var balance: Double = 0.0
    var transactions: [Transaction] = []
    
    init(privateKey: Data) {
        self.privateKey = privateKey
        self.publicKey = KeyManager.shared.getPublicKey(from: privateKey) ?? Data()
        self.address = generateAddress()
    }
    
    private func generateAddress() -> String {
        let publicKeyHash = SHA256.hash(data: publicKey)
        return publicKeyHash.map { String(format: "%02x", $0) }.joined()
    }
}

// MARK: - Transaction Model
struct Transaction {
    let from: String
    let to: String
    let amount: Double
    let timestamp: Date
    let signature: Data?
    let transactionHash: String
    
    init(from: String, to: String, amount: Double, privateKey: Data) {
        self.from = from
        self.to = to
        self.amount = amount
        self.timestamp = Date()
        self.signature = KeyManager.shared.signTransaction(
            transaction: generateTransactionData(),
            privateKey: privateKey
        )
        self.transactionHash = generateTransactionHash()
    }
    
    private func generateTransactionData() -> Data {
        let data = "\(from)\(to)\(amount)\(timestamp.timeIntervalSince1970)".data(using: .utf8)!
        return data
    }
    
    private func generateTransactionHash() -> String {
        let data = generateTransactionData()
        let hash = SHA256.hash(data: data)
        return hash.map { String(format: "%02x", $0) }.joined()
    }
}

